// Recebe todos os cards com due_date
const items = $input.all();

if (!items || items.length === 0) {
  console.log('Nenhum card recebido');
  return [];
}

console.log(`Total de cards recebidos: ${items.length}`);

const agora = new Date();
const resultado = [];

for (const item of items) {
  const card = item.json;
  if (!card.due_date || !card.titulo) continue;

  const dueDateUTC = new Date(card.due_date);
  const diffMs    = dueDateUTC.getTime() - agora.getTime();
  const diffHoras  = diffMs / (1000 * 60 * 60);

  console.log(`Card: ${card.titulo.substring(0,40)} | diffHoras: ${diffHoras.toFixed(1)}`);

  // Janelas de ±1h para cada marco
  const is2dias = diffHoras >= 47 && diffHoras <= 49;   // exatamente 2 dias
  const is1dia  = diffHoras >= 23 && diffHoras <= 25;   // exatamente 1 dia
  const isHoje  = diffHoras >= -1 && diffHoras <= 1;    // exatamente agora (±1h)

  if (!is2dias && !is1dia && !isHoje) continue;

  // Formatar data e hora (Brasil)
  const dataFormatada = dueDateUTC.toLocaleDateString('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    weekday: 'long',
    day: '2-digit',
    month: 'long',
    year: 'numeric'
  });
  const horaFormatada = dueDateUTC.toLocaleTimeString('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    hour: '2-digit',
    minute: '2-digit'
  });

  // Título resumido
  const tituloResumido = card.titulo.length > 120
    ? card.titulo.substring(0, 120) + '...'
    : card.titulo;

  // Tipo do lembrete
  let tipoLembrete, emoji, urgencia;
  if (is2dias) {
    tipoLembrete = '2 DIAS';
    emoji = '📅';
    urgencia = 'Prepare a documentação e análise jurídica!';
  } else if (is1dia) {
    tipoLembrete = '1 DIA';
    emoji = '⚠️';
    urgencia = 'AMANHÃ! Confirme sua participação.';
  } else {
    tipoLembrete = 'HOJE';
    emoji = '🔨';
    urgencia = 'LEILÃO HOJE! Acesse agora.';
  }

  // Montar mensagem WhatsApp
  const linhas = [
    `${emoji} *LEMBRETE DE LEILÃO — FALTAM ${tipoLembrete}*`,
    ``,
    `🏠 *Imóvel:*`,
    tituloResumido,
    ``,
    `📆 *Data:* ${dataFormatada}`,
    `🕐 *Horário:* ${horaFormatada}`,
    ``,
    `⚡ ${urgencia}`,
  ];

  if (card.link_leilao) {
    linhas.push(``);
    linhas.push(`🔗 *Link do leilão:*`);
    linhas.push(card.link_leilao);
  }

  linhas.push(``);
  linhas.push(`_FlowDesck · Ruah Systems_`);

  resultado.push({
    json: {
      id: card.id,
      titulo: card.titulo,
      due_date: card.due_date,
      link_leilao: card.link_leilao || '',
      mensagem: linhas.join('\n'),
      tipoLembrete,
      dataFormatada,
      horaFormatada,
      tituloResumido
    }
  });
}

console.log(`Lembretes para enviar: ${resultado.length}`);
return resultado;
